/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Features:
 * - JSON payload formatting from notification data
 * - URL validation
 * - Pluggable transport for testability (inject real HTTP client or mock)
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents the JSON body sent to the webhook endpoint.
 */
export interface WebhookRequestBody {
  notificationId: string;
  type: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

/**
 * Transport interface — abstracts the actual HTTP POST mechanism.
 * Implement this with fetch, axios, or a test double.
 */
export interface WebhookTransport {
  post(url: string, body: WebhookRequestBody, headers: Record<string, string>): Promise<{ statusCode: number }>;
}

export interface WebhookConfig {
  /** Webhook endpoint URL */
  url: string;
  /** Optional secret for signing requests */
  secret?: string;
  /** HTTP transport implementation */
  transport: WebhookTransport;
}

const URL_REGEX = /^https?:\/\/\S+/;

function isValidUrl(url: string): boolean {
  return URL_REGEX.test(url);
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');

  constructor(private config: WebhookConfig) {
    if (!isValidUrl(config.url)) {
      throw new Error(`Invalid webhook URL: ${config.url}`);
    }
  }

  /**
   * Format a notification payload into the JSON body for the webhook POST.
   */
  formatPayload(payload: NotificationPayload): WebhookRequestBody {
    return {
      notificationId: payload.id,
      type: payload.type,
      channel: payload.channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      createdAt: payload.createdAt.toISOString(),
      metadata: payload.metadata,
    };
  }

  /**
   * Send a webhook notification.
   * Formats the payload as JSON and POSTs it to the configured URL.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const requestBody = this.formatPayload(payload);

      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
      };

      if (this.config.secret) {
        headers['X-Webhook-Secret'] = this.config.secret;
      }

      this.logger.info(`Sending webhook to ${this.config.url} for notification ${payload.id}`);

      const response = await this.config.transport.post(this.config.url, requestBody, headers);

      if (response.statusCode >= 200 && response.statusCode < 300) {
        this.logger.info(`Webhook delivered successfully: ${payload.id} (status ${response.statusCode})`);

        return {
          success: true,
          notificationId: payload.id,
          channel: this.channel,
          deliveredAt: new Date(),
        };
      }

      const errorMessage = `Webhook returned status ${response.statusCode}`;
      this.logger.error(`Webhook delivery failed for ${payload.id}: ${errorMessage}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: errorMessage,
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send webhook for ${payload.id}: ${errorMessage}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: errorMessage,
      };
    }
  }
}

