import { describe, it, expect, beforeEach, vi } from 'vitest';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { WebhookConfig, WebhookTransport, WebhookRequestBody } from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function createMockTransport() {
  return {
    post: vi.fn<(url: string, body: WebhookRequestBody, headers: Record<string, string>) => Promise<{ statusCode: number }>>().mockResolvedValue({
      statusCode: 200,
    }),
  };
}

function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'webhook',
    recipient: 'user-123',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-03-30T12:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let transport: ReturnType<typeof createMockTransport>;
  let config: WebhookConfig;
  let adapter: WebhookAdapter;

  beforeEach(() => {
    transport = createMockTransport();
    config = { url: 'https://hooks.example.com/notify', transport };
    adapter = new WebhookAdapter(config);
  });

  describe('channel', () => {
    it('should report webhook as its channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('constructor', () => {
    it('should reject invalid URLs', () => {
      expect(() => new WebhookAdapter({ url: 'not-a-url', transport })).toThrow('Invalid webhook URL');
    });

    it('should reject empty URLs', () => {
      expect(() => new WebhookAdapter({ url: '', transport })).toThrow('Invalid webhook URL');
    });

    it('should accept http URLs', () => {
      expect(() => new WebhookAdapter({ url: 'http://localhost:3000/hook', transport })).not.toThrow();
    });

    it('should accept https URLs', () => {
      expect(() => new WebhookAdapter({ url: 'https://hooks.example.com/notify', transport })).not.toThrow();
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook request body', () => {
      const payload = createPayload();
      const body = adapter.formatPayload(payload);

      expect(body.notificationId).toBe('notif-0001');
      expect(body.type).toBe('order-confirmation');
      expect(body.channel).toBe('webhook');
      expect(body.recipient).toBe('user-123');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Widget x2');
      expect(body.priority).toBe('normal');
      expect(body.createdAt).toBe('2026-03-30T12:00:00.000Z');
    });

    it('should include metadata when present', () => {
      const payload = createPayload({
        metadata: { orderId: 'order-1', trackingUrl: 'https://track.example.com/123' },
      });
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toEqual({ orderId: 'order-1', trackingUrl: 'https://track.example.com/123' });
    });

    it('should omit metadata when not present', () => {
      const payload = createPayload();
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toBeUndefined();
    });
  });

  describe('send', () => {
    it('should POST to the configured URL and return success', async () => {
      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();

      expect(transport.post).toHaveBeenCalledOnce();
      const [url, body, headers] = transport.post.mock.calls[0]!;
      expect(url).toBe('https://hooks.example.com/notify');
      expect(body.notificationId).toBe('notif-0001');
      expect(headers['Content-Type']).toBe('application/json');
    });

    it('should include secret header when configured', async () => {
      const adapterWithSecret = new WebhookAdapter({
        url: 'https://hooks.example.com/notify',
        secret: 'my-secret-token',
        transport,
      });

      const payload = createPayload();
      await adapterWithSecret.send(payload);

      const [, , headers] = transport.post.mock.calls[0]!;
      expect(headers['X-Webhook-Secret']).toBe('my-secret-token');
    });

    it('should not include secret header when not configured', async () => {
      const payload = createPayload();
      await adapter.send(payload);

      const [, , headers] = transport.post.mock.calls[0]!;
      expect(headers['X-Webhook-Secret']).toBeUndefined();
    });

    it('should return failure when transport throws', async () => {
      transport.post.mockRejectedValue(new Error('Connection refused'));

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
    });

    it('should return failure for non-2xx status codes', async () => {
      transport.post.mockResolvedValue({ statusCode: 500 });

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Webhook returned status 500');
    });

    it('should return failure for 4xx status codes', async () => {
      transport.post.mockResolvedValue({ statusCode: 404 });

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Webhook returned status 404');
    });

    it('should succeed for 201 status code', async () => {
      transport.post.mockResolvedValue({ statusCode: 201 });

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.error).toBeUndefined();
    });

    it('should handle non-Error thrown values', async () => {
      transport.post.mockRejectedValue('network failure');

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('network failure');
    });
  });
});
